+/// Get a specific attribute from all edges.
+#[must_use]
+pub fn get_edge_attributes(
+    graph: &Graph,
+    name: &str,
+) -> std::collections::HashMap<(String, String), String> {
+    let mut result = std::collections::HashMap::new();
+    for edge in graph.edges_ordered() {
